 * // RawAudio {
 * //   audio: Float32Array(95232) [-0.000482565927086398, -0.0004853440332226455, ...],
 * //   sampling_rate: 44100
 * // }

        }

        return toReturn.length > 1 ? toReturn : toReturn[0];
    }
}

